<textarea id="raw" style="display:none">$1</textarea>

<div id="trmb"></div>
<script>
(function(){
  function g(id){return document.getElementById(id);}
  function esc(s){return String(s==null?'':s).replace(/[<>&]/g,function(c){return{'<':'&lt;','>':'&gt;','&':'&amp;'}[c];});}
  function has(v){return v!=null&&String(v).trim()!=='';}
  var raw=(g('raw').value||'').replace(/<\/?TR_MISSIONS>/gi,'').trim();
  var D={};try{if(raw&&raw.charAt(0)==='{')D=JSON.parse(raw);}catch(e){}
  var th=(D.ui_lang==='th');
  function L(en,t){return th?t:en;}
  var ST={open:['OPEN','เปิดรับ'],taken:['TAKEN','มีผู้รับ'],done:['DONE','สำเร็จ'],failed:['FAILED','ล้มเหลว']};
  var notes='';
  var ms=(D.missions||[]);
  if(ms.length){
    ms.forEach(function(m){
      var st=(m.status||'open').toLowerCase(); if(!ST[st])st='open';
      var foot='';
      if(has(m.reward)||has(m.poster)){
        foot='<div class="nfoot">'+
          (has(m.reward)?'<div class="reward"><small>'+L('Reward','รางวัล')+'</small>'+esc(m.reward)+'</div>':'<div></div>')+
          (has(m.poster)?'<div class="loc">— '+esc(m.poster)+'</div>':'')+'</div>';
      }
      notes+='<div class="note"><span class="tack tl"></span><span class="tack tr"></span><span class="tack bl"></span><span class="tack br"></span>'+
        '<div class="stamp '+st+'">'+L(ST[st][0],ST[st][1])+'</div>'+
        '<div class="ntop">'+(has(m.rank)?'<div class="rank">'+esc(m.rank)+'</div>':'')+
        '<div class="nhd"><div class="ntitle">'+esc(m.title)+'</div>'+(has(m.type)?'<div class="ntype">'+esc(m.type)+'</div>':'')+'</div></div>'+
        (has(m.desc)?'<div class="ndesc">'+esc(m.desc)+'</div>':'')+foot+'</div>';
    });
  } else {
    notes='<div class="bare">'+L('The board is bare.','กระดานว่างเปล่า')+'</div>';
  }
  g('trmb').innerHTML='<div class="hdr"><div class="t">'+L('GUILD MISSION BOARD','กระดานภารกิจกิลด์')+'</div>'+
    (has(D.board)?'<div class="s">'+esc(D.board)+'</div>':'')+'</div><div class="notes">'+notes+'</div>';
})();
</script>
